<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=htmlspecialchars($meta['titulo'],ENT_QUOTES,'UTF-8')?></title><link rel="stylesheet" href="<?=BASE_URL?>/public/css/estilos.css"><link rel="stylesheet" href="<?=BASE_URL?>/public/css/admin.css"></head><body class="admin-page"><?php require __DIR__.'/../partials/navbar.php';?><div class="admin-layout"><?php require __DIR__.'/../partials/sidebar.php';?><main class="admin-main"><?php require __DIR__.'/partials/encabezado_reporte.php';?>
<form class="admin-report-filters" method="get"><input type="hidden" name="ruta" value="admin-reporte-<?=$tipo?>"><label>Buscar<input name="buscar" value="<?=htmlspecialchars($filtros['buscar'],ENT_QUOTES,'UTF-8')?>"></label><?php if($tipo!=='alumnos'):?><label>Desde<input type="date" name="desde" value="<?=$filtros['desde']?>"></label><label>Hasta<input type="date" name="hasta" value="<?=$filtros['hasta']?>"></label><?php endif;?><?php if(in_array($tipo,['pagos','adeudos','prorrogas'],true)):?><label>Periodo<input type="month" name="periodo" value="<?=$filtros['periodo']?>"></label><?php endif;?><label>Estado<select name="estado"><option value="">Todos</option><?php $estados=['pagos'=>['Pendiente','Validado','Rechazado'],'adeudos'=>['Pendiente','Pagado'],'alumnos'=>['Activo','Inactivo'],'prorrogas'=>['Vigente','Vencida','Finalizada'],'aclaraciones'=>['Abierta','En revisión','Resuelta','Rechazada']];foreach($estados[$tipo]as$e):?><option <?=$filtros['estado']===$e?'selected':''?>><?=$e?></option><?php endforeach;?></select></label><?php if($tipo==='pagos'):?><label>Origen<select name="origen"><option value="">Todos</option><?php foreach(['Portal Alumno','Manual Administrador']as$x):?><option <?=$filtros['origen']===$x?'selected':''?>><?=$x?></option><?php endforeach;?></select></label><label>Método<select name="metodo"><option value="">Todos</option><?php foreach(['Tarjeta','Efectivo']as$x):?><option <?=$filtros['metodo']===$x?'selected':''?>><?=$x?></option><?php endforeach;?></select></label><?php elseif($tipo==='adeudos'):?><label>Recargo<select name="recargo"><option value="">Todos</option><option value="con" <?=$filtros['recargo']==='con'?'selected':''?>>Con recargo</option><option value="sin" <?=$filtros['recargo']==='sin'?'selected':''?>>Sin recargo</option></select></label><?php elseif($tipo==='alumnos'):?><label>Carrera<select name="carrera"><option value="">Todas</option><?php foreach($opciones['carreras']as$x):?><option <?=$filtros['carrera']===$x?'selected':''?>><?=htmlspecialchars($x,ENT_QUOTES,'UTF-8')?></option><?php endforeach;?></select></label><label>Grupo<select name="grupo"><option value="">Todos</option><?php foreach($opciones['grupos']as$x):?><option <?=$filtros['grupo']===$x?'selected':''?>><?=htmlspecialchars($x,ENT_QUOTES,'UTF-8')?></option><?php endforeach;?></select></label><?php elseif($tipo==='aclaraciones'):?><label>Tipo<select name="tipo_aclaracion"><option value="">Todos</option><?php foreach(['Pago no reflejado','Importe incorrecto','Adeudo duplicado','Recargo incorrecto','Comprobante no recibido','Otro']as$x):?><option <?=$filtros['tipo']===$x?'selected':''?>><?=$x?></option><?php endforeach;?></select></label><?php endif;?><button>Filtrar</button></form>
<div class="admin-report-summary"><?php foreach($resumen as$k=>$v):?><article><span><?=htmlspecialchars(ucfirst(str_replace('_',' ',$k)),ENT_QUOTES,'UTF-8')?></span><strong><?=str_contains($k,'monto')?'$'.number_format((float)$v,2):number_format((float)$v)?></strong></article><?php endforeach;?></div><div class="admin-report-table-wrapper"><table class="admin-report-table"><thead><tr><?php foreach($meta['columnas']as$h):?><th><?=htmlspecialchars($h,ENT_QUOTES,'UTF-8')?></th><?php endforeach;?></tr></thead><tbody><?php if(!$registros):?><tr><td colspan="<?=count($meta['columnas'])?>" class="admin-report-empty">No se encontraron registros con los filtros seleccionados.</td></tr><?php else:foreach($registros as$row):?><tr><?php foreach(array_keys($meta['columnas'])as$k):?><td><?=htmlspecialchars($this->valor($k,$row[$k]??''),ENT_QUOTES,'UTF-8')?></td><?php endforeach;?></tr><?php endforeach;endif;?></tbody></table></div><?php require __DIR__.'/partials/paginacion.php';require __DIR__.'/../partials/footer.php';?></main></div><script src="<?=BASE_URL?>/public/js/admin.js"></script></body></html>
